/**
 * Подтема PlasmaHomeDsTheme.OnDark
 */
@Composable
public fun PlasmaHomeDsTheme.OnDark(
    isDark: Boolean = isSystemInDarkTheme(),
    content: @Composable
    () -> Unit,
) {
    val currentColors = LocalPlasmaHomeDsColors.current
    val overrideColors = currentColors.copyAttrs(OnDarkColorsOverride)
    val currentGradients = LocalPlasmaHomeDsGradients.current
    val overrideGradients = currentGradients.copyAttrs(OnDarkGradientsOverride)
    PlasmaHomeDsTheme(
        colors = overrideColors,
        gradients = overrideGradients,
        content = content,
    )
}
